package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

class ReflectionAccessFilterHelperTest {

  @Test
  void testIsAnyPlatformType_withAndroidType() throws Exception {
    Class<?> androidClass = createDummyClass("android.dummy.Class");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(androidClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinPackage() throws Exception {
    Class<?> kotlinClass = createDummyClass("kotlin.dummy.Class");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinClass));
  }

  @Test
  void testIsAnyPlatformType_withKotlinxPackage() throws Exception {
    Class<?> kotlinxClass = createDummyClass("kotlinx.dummy.Class");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(kotlinxClass));
  }

  @Test
  void testIsAnyPlatformType_withScalaPackage() throws Exception {
    Class<?> scalaClass = createDummyClass("scala.dummy.Class");
    assertTrue(ReflectionAccessFilterHelper.isAnyPlatformType(scalaClass));
  }

  @Test
  void testIsAnyPlatformType_withOtherClass() throws Exception {
    Class<?> otherClass = createDummyClass("com.example.OtherClass");
    assertFalse(ReflectionAccessFilterHelper.isAnyPlatformType(otherClass));
  }

  /**
   * Creates a dummy class with the specified fully qualified name dynamically.
   * This allows us to simulate classes from different packages.
   */
  private static Class<?> createDummyClass(String className) throws Exception {
    String simpleName = className.substring(className.lastIndexOf('.') + 1);
    String packageName = className.substring(0, className.lastIndexOf('.'));
    String source =
        "package " + packageName + ";\n" +
        "public class " + simpleName + " {\n" +
        "}";

    InMemoryJavaCompiler compiler = new InMemoryJavaCompiler();
    return compiler.compile(className, source);
  }

  /**
   * Simple in-memory Java compiler to compile source code strings into Class<?> at runtime.
   */
  private static class InMemoryJavaCompiler {
    private final javax.tools.JavaCompiler compiler;
    private final javax.tools.StandardJavaFileManager standardFileManager;

    InMemoryJavaCompiler() {
      compiler = javax.tools.ToolProvider.getSystemJavaCompiler();
      if (compiler == null) {
        throw new IllegalStateException("No Java compiler available. " +
            "Make sure to run tests with a JDK, not a JRE.");
      }
      standardFileManager = compiler.getStandardFileManager(null, null, null);
    }

    Class<?> compile(String className, String source) throws Exception {
      JavaSourceFromString jsfs = new JavaSourceFromString(className, source);
      java.util.List<javax.tools.JavaFileObject> compilationUnits = java.util.Collections.singletonList(jsfs);

      javax.tools.JavaFileManager fileManager = new ForwardingJavaFileManager<javax.tools.StandardJavaFileManager>(standardFileManager) {
        private final java.util.Map<String, ByteArrayJavaClass> compiledClasses = new java.util.HashMap<>();

        @Override
        public javax.tools.JavaFileObject getJavaFileForOutput(javax.tools.JavaFileManager.Location location,
                                                               String className,
                                                               javax.tools.JavaFileObject.Kind kind,
                                                               javax.tools.FileObject sibling) {
          ByteArrayJavaClass byteClass = new ByteArrayJavaClass(className);
          compiledClasses.put(className, byteClass);
          return byteClass;
        }

        ClassLoader getClassLoader() {
          return new ClassLoader(getClass().getClassLoader()) {
            @Override
            protected Class<?> findClass(String name) throws ClassNotFoundException {
              ByteArrayJavaClass byteClass = compiledClasses.get(name);
              if (byteClass == null) {
                return super.findClass(name);
              }
              byte[] bytes = byteClass.getBytes();
              return defineClass(name, bytes, 0, bytes.length);
            }
          };
        }
      };

      javax.tools.JavaCompiler.CompilationTask task = compiler.getTask(null, fileManager, null, null, null, compilationUnits);
      Boolean result = task.call();
      if (result == null || !result) {
        throw new IllegalStateException("Compilation failed");
      }
      return ((ForwardingJavaFileManager<?>) fileManager).getClassLoader().loadClass(className);
    }

    private static class JavaSourceFromString extends javax.tools.SimpleJavaFileObject {
      final String code;

      JavaSourceFromString(String name, String code) {
        super(java.net.URI.create("string:///" + name.replace('.', '/') + javax.tools.JavaFileObject.Kind.SOURCE.extension),
            javax.tools.JavaFileObject.Kind.SOURCE);
        this.code = code;
      }

      @Override
      public CharSequence getCharContent(boolean ignoreEncodingErrors) {
        return code;
      }
    }

    private static class ByteArrayJavaClass extends javax.tools.SimpleJavaFileObject {
      private final java.io.ByteArrayOutputStream baos = new java.io.ByteArrayOutputStream();

      ByteArrayJavaClass(String name) {
        super(java.net.URI.create("bytes:///" + name.replace('.', '/') + javax.tools.JavaFileObject.Kind.CLASS.extension),
            javax.tools.JavaFileObject.Kind.CLASS);
      }

      @Override
      public java.io.OutputStream openOutputStream() {
        return baos;
      }

      byte[] getBytes() {
        return baos.toByteArray();
      }
    }
  }
}
